using UnityEngine;using System;
public class AdManager : MonoBehaviour{public static AdManager Instance{get;private set;}public enum RewardType{Revive,DoubleScore}public Action<RewardType> OnRewardGranted;private bool adsRemoved;private void Awake(){if(Instance==null)Instance=this;else{Destroy(gameObject);return;}adsRemoved=PlayerPrefs.GetInt("AdsRemoved",0)==1;}public void ShowRewardedAd(RewardType rt){GrantReward(rt);}public bool IsRewardedAdReady()=>!adsRemoved;private void GrantReward(RewardType rt){switch(rt){case RewardType.Revive:GameManager.Instance?.TryRevive();break;case RewardType.DoubleScore:ScoreManager.Instance?.DoubleScore();break;}OnRewardGranted?.Invoke(rt);}public void RemoveAds(){adsRemoved=true;PlayerPrefs.SetInt("AdsRemoved",1);PlayerPrefs.Save();}}